// src/icsToJson.ts
var NEW_LINE = /\r\n|\n|\r/;
var EVENT = "VEVENT";
var EVENT_START = "BEGIN";
var EVENT_END = "END";
var START_DATE = "DTSTART";
var END_DATE = "DTEND";
var DESCRIPTION = "DESCRIPTION";
var SUMMARY = "SUMMARY";
